private void DeployNewCardToPosition(Player player, BattleField battleField, BattleFieldPosition position, Card originCardObject)
{
    ActorRef<Card> visionCard = NewActor<Card>();
    Card cardObject = GetActorObject(visionCard);
    AccurateCardPosition toPos = GetAccuratePosition(position, player.GetPlayerPosition());
    FillAndPlaceCard(cardObject, visionCard, toPos, originCardObject);
