private AccurateCardPosition GetAccuratePosition(BattleFieldPosition pos, PlayerPosition playerPos)
{
    return new AccurateCardPosition
    {
        BattleFieldPosition = pos,
        PlayerPosition = playerPos
    };
}

private void FillAndPlaceCard(Card card, ActorRef<Card> visionCard, AccurateCardPosition toPos, Card originCardObject)
{
    card.SetCardPosition((CardPosition)toPos);
    CardID cardID = new CardID
    {
        ID = visionCard.ID.ID
    };
    CGDataTable.FillCard(card, originCardObject);
    card.SetCardID(cardID);
    card.SetDeployInterval(GameConfig.MinionDeployGCD);
    card.SetAutoAttackInterval(GameConfig.MinionAutoAttackInterval);
    card.SetOwnerPlayer(originCardObject.GetOwnerPlayer());
    card.SetIsDeployed(false);
    card.DeployTimer.Start(this, GameConfig.MinionDeployGCD, 1);
}

private void DeployVisionCardsIfNeeded(Card originCardObject, Player playerObject, BattleField battleField, AccurateCardPosition accurateCardPosition)
{
    List<Card> cards = new List<Card> { originCardObject };

    // Refactored code
    CheckAndDeployCard(battleField, playerObject, accurateCardPosition, originCardObject, isLeft: true, cards);
    CheckAndDeployCard(battleField, playerObject, accurateCardPosition, originCardObject, isLeft: false, cards);

